        int N = Integer.parseInt(st.nextToken());
        st = new StringTokenizer(br.readLine());
        long PU = Long.parseLong(st.nextToken());
        long PL = Long.parseLong(st.nextToken());
        long PD = Long.parseLong(st.nextToken());
        long PR = Long.parseLong(st.nextToken());
        for(int i=0;i<N;i++){
            st = new StringTokenizer(br.readLine());
